import React, { useState } from 'react';

function ProjectsPage({ data }) {
  const [selectedCategory, setSelectedCategory] = useState('All');

  if (!data || data.length === 0) return null;

  // Extract unique categories/companies
  const allCategories = ['All', ...new Set(data.map(p => p.company.split(',')[1]?.trim()))];

  const filteredProjects = selectedCategory === 'All' 
    ? data 
    : data.filter(p => p.company.includes(selectedCategory));

  return (
    <section id="projects-page" className="bg-white py-8 md:py-12">
      <div className="max-w-7xl mx-auto px-4">
        {/* Header */}
        <div className="mb-16">
          <p className="text-xs uppercase tracking-widest text-gray-500 font-semibold mb-4">
            Projects
          </p>
          <h1 className="text-5xl md:text-6xl font-black text-gray-900 mb-4">My Projects</h1>
          <p className="text-lg text-gray-600 max-w-3xl leading-relaxed">
            A showcase of my work across web development, design, and AI projects
          </p>
        </div>

        {/* Category Filter */}
        <div className="flex flex-wrap gap-3 mb-16">
          {allCategories.map((category) => (
            <button
              key={category}
              onClick={() => setSelectedCategory(category)}
              className={`px-6 py-2 uppercase tracking-wider text-xs font-bold transition-all duration-200 border ${
                selectedCategory === category
                  ? 'bg-gray-900 text-white border-gray-900'
                  : 'bg-white text-gray-900 border-gray-300 hover:border-gray-900'
              }`}
            >
              {category}
            </button>
          ))}
        </div>

        {/* Projects Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {filteredProjects.map((project) => (
            <div
              key={project.id}
              className="group border border-gray-200 hover:border-gray-900 transition-all duration-300"
            >
              {/* Project Image */}
              <div className="relative h-56 bg-gray-200 flex items-center justify-center overflow-hidden border-b border-gray-200">
                {project.image ? (
                  <img
                    src={project.image}
                    alt={project.title}
                    className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-300"
                  />
                ) : (
                  <span className="text-6xl group-hover:scale-125 transition-transform duration-300 text-gray-400">
                    {project.icon}
                  </span>
                )}
                <div className="absolute inset-0 bg-black/0 group-hover:bg-black/5 transition-colors duration-300"></div>
              </div>

              {/* Project Content */}
              <div className="p-6">
                <h3 className="text-xl font-black text-gray-900 mb-2 group-hover:text-gray-600 transition-colors">
                  {project.title}
                </h3>
                <p className="text-gray-600 font-semibold text-sm mb-3 uppercase tracking-wide">
                  {project.company}
                </p>

                {project.description && (
                  <p className="text-gray-600 text-sm mb-4 leading-relaxed line-clamp-3">
                    {project.description}
                  </p>
                )}

                {/* Tech Stack */}
                {project.tags && project.tags.length > 0 && (
                  <div className="flex flex-wrap gap-2 mb-5">
                    {project.tags.slice(0, 3).map((tag, idx) => (
                      <span
                        key={idx}
                        className="inline-block bg-gray-100 text-gray-700 px-3 py-1 text-xs font-semibold border border-gray-300"
                      >
                        {tag}
                      </span>
                    ))}
                    {project.tags.length > 3 && (
                      <span className="inline-block bg-white text-gray-600 px-3 py-1 text-xs font-semibold border border-gray-300">
                        +{project.tags.length - 3}
                      </span>
                    )}
                  </div>
                )}

                {/* View Project Button */}
                {project.link && (
                  <a
                    href={project.link}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="inline-flex items-center gap-2 text-gray-900 font-black uppercase tracking-wider text-xs hover:text-gray-600 transition-colors group/link"
                  >
                    View Project
                    <span className="group-hover/link:translate-x-1 transition-transform">→</span>
                  </a>
                )}
              </div>
            </div>
          ))}
        </div>

        {/* No Projects Message */}
        {filteredProjects.length === 0 && (
          <div className="text-center py-12">
            <p className="text-lg text-gray-600">No projects found in this category</p>
          </div>
        )}
      </div>
    </section>
  );
}

export default ProjectsPage;
